// ========================================
// WF1 v3 - EXTRACT CLARIFICATION DATA
// With Email Fallback Chain + Trigger Condition
// Updated: 28/12/2025
// ========================================

const clarification = $input.first().json;
const properties = clarification.properties || {};

// ========== HELPER: Get field by type + keywords ==========
const getFieldByType = (type, keywords) => {
  for (const [fieldName, fieldData] of Object.entries(properties)) {
    if (fieldData.type !== type) continue;
    const nameLC = fieldName.toLowerCase();
    if (keywords.some(kw => nameLC.includes(kw.toLowerCase()))) {
      if (type === 'title') return { value: fieldData.title?.[0]?.plain_text || '', fieldName };
      if (type === 'rich_text') return { value: fieldData.rich_text?.[0]?.plain_text || '', fieldName };
      if (type === 'select') return { value: fieldData.select?.name || '', fieldName };
      if (type === 'date') return { value: fieldData.date?.start || '', fieldName };
      if (type === 'email') return { value: fieldData.email || '', fieldName };
    }
  }
  return { value: '', fieldName: null };
};

// ========== EXTRACT CORE FIELDS ==========
// Title (required)
let tieuDe = '';
for (const [name, data] of Object.entries(properties)) {
  if (data.type === 'title') {
    tieuDe = data.title?.[0]?.plain_text || '';
    break;
  }
}

// Other fields
const noiDungGoc = getFieldByType('rich_text', ['nội dung', 'gốc']);
const t2NhiemVu = getFieldByType('rich_text', ['nhiệm vụ', 't2']);
const t3ChiTieu = getFieldByType('rich_text', ['chỉ tiêu', 't3']);
const t4ThoiHan = getFieldByType('date', ['thời hạn', 't4', 'deadline']);
const uuTien = getFieldByType('select', ['ưu tiên', 'priority']);
const nguonGiaoViec = getFieldByType('select', ['nguồn']);
const tinhTrang = getFieldByType('select', ['tình trạng', 'status']);

// ========== EMAIL FALLBACK CHAIN ==========
// Priority 1: Direct email field "📧 Email đầu mối"
const emailDauMoi = getFieldByType('email', ['email', 'đầu mối']);

// Priority 2: HR Relation (will be resolved in next node)
let hrRelationId = null;
for (const [fieldName, fieldData] of Object.entries(properties)) {
  if (fieldData.type === 'relation' && fieldData.relation?.length > 0) {
    const nameLC = fieldName.toLowerCase();
    if (nameLC.includes('hr') || nameLC.includes('người nhận')) {
      hrRelationId = fieldData.relation[0].id;
      break;
    }
  }
}

// Priority 3: Fallback emails
const FALLBACK_PRIMARY = 'vynnl@esuhai.com';
const FALLBACK_CC = 'hoangkha@esuhai.com';

// Determine email source
let emailSource = 'fallback';
let primaryEmail = '';

if (emailDauMoi.value && emailDauMoi.value.includes('@')) {
  primaryEmail = emailDauMoi.value;
  emailSource = 'direct_field';
} else if (hrRelationId) {
  emailSource = 'hr_lookup';
}

// ========== CHECK TRIGGER CONDITION ==========
// Only trigger if status is "🆕 Mới tạo"
const shouldTrigger = tinhTrang.value === '🆕 Mới tạo';

// ========== LOG FOR DEBUGGING ==========
console.log('=== WF1 EXTRACT v3 ===');
console.log('Clarification ID:', clarification.id);
console.log('Tiêu đề:', tieuDe);
console.log('Tình trạng:', tinhTrang.value);
console.log('Should Trigger:', shouldTrigger);
console.log('Email Source:', emailSource);
console.log('Primary Email:', primaryEmail);
console.log('HR Relation ID:', hrRelationId);

// ========== OUTPUT ==========
return {
  // Clarification info
  clarificationId: clarification.id,
  clarificationUrl: clarification.url || 'https://www.notion.so/' + clarification.id.replace(/-/g, ''),

  // Trigger condition
  shouldTrigger,
  tinhTrang: tinhTrang.value,

  // Content fields
  tieuDe,
  noiDungGoc: noiDungGoc.value,
  t2NhiemVu: t2NhiemVu.value,
  t3ChiTieu: t3ChiTieu.value,
  t4ThoiHan: t4ThoiHan.value,
  uuTien: uuTien.value,
  nguonGiaoViec: nguonGiaoViec.value || 'CEO',

  // Email chain
  emailSource,
  primaryEmail,
  hrRelationId,
  fallbackPrimary: FALLBACK_PRIMARY,
  fallbackCC: FALLBACK_CC,

  // 4T Check
  has4T: Boolean(tieuDe && t2NhiemVu.value && t3ChiTieu.value && t4ThoiHan.value)
};

// ========================================
// WF1 v3 - BUILD PREFILL URL
// BRANCH: Direct Email (no HR lookup needed)
// ========================================

const data = $input.first().json;

// Email already available from direct field
const hrEmail = data.primaryEmail;
const hoVaTen = 'Anh/Chị'; // Unknown without HR lookup

console.log('=== DIRECT EMAIL BRANCH ===');
console.log('Using direct email:', hrEmail);

// ========== BUILD PREFILL URL ==========
const FORM_URL = 'https://docs.google.com/forms/d/e/1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw/viewform?usp=pp_url';

const ENTRY_IDS = {
  'clarificationId': 'entry.1684171280',
  'tieuDe': 'entry.1878008034',
  'noiDungGoc': 'entry.1953342780',
  't2NhiemVu': 'entry.1839616630',
  't3ChiTieu': 'entry.649583359',
  't4ThoiHan': 'entry.1319518938',
  'uuTien': 'entry.1910876946',
  'nguonGiaoViec': 'entry.1661283634'
};

const params = {
  [ENTRY_IDS['clarificationId']]: data.clarificationId,
  [ENTRY_IDS['tieuDe']]: data.tieuDe,
  [ENTRY_IDS['noiDungGoc']]: data.noiDungGoc,
  [ENTRY_IDS['t2NhiemVu']]: data.t2NhiemVu,
  [ENTRY_IDS['t3ChiTieu']]: data.t3ChiTieu,
  [ENTRY_IDS['t4ThoiHan']]: data.t4ThoiHan,
  [ENTRY_IDS['uuTien']]: data.uuTien,
  [ENTRY_IDS['nguonGiaoViec']]: data.nguonGiaoViec
};

const queryString = Object.keys(params)
  .map(key => key + '=' + encodeURIComponent(params[key] || ''))
  .join('&');

const prefillUrl = FORM_URL + '&' + queryString;

// Status message
const statusMessage = data.has4T 
  ? '✅ Chỉ đạo đã có đủ 4T. Vui lòng XÁC NHẬN và CAM KẾT thực hiện.'
  : '⚠️ Chỉ đạo còn thiếu thông tin. Vui lòng BỔ SUNG các trường còn trống.';

return {
  ...data,
  hrEmail,
  hoVaTen,
  ccEmail: '', // No CC needed for direct email
  prefillUrl,
  statusMessage,
  emailResolutionLog: ['✅ Used direct email field: ' + hrEmail]
};

// ========================================
// WF1 v3 - BUILD PREFILL URL
// BRANCH: HR Lookup OR Fallback
// ========================================

const clarData = $('Extract Clarification Data').first().json;
let hrPage = null;

// Try to get HR data if available
try {
  hrPage = $('Get HR Page').first().json;
} catch (e) {
  console.log('HR Page not available:', e.message);
}

// ========== RESOLVE EMAIL ==========
let hrEmail = '';
let hoVaTen = 'Anh/Chị';
let ccEmail = '';
let emailResolutionLog = [];

// Try HR lookup first
if (hrPage && hrPage.properties) {
  const hrProperties = hrPage.properties;

  for (const [fieldName, fieldData] of Object.entries(hrProperties)) {
    // Get Email
    if (fieldData.type === 'email' && fieldData.email) {
      hrEmail = fieldData.email;
      emailResolutionLog.push('✅ Used HR email: ' + hrEmail);
    }
    // Get Name
    if (fieldData.type === 'title') {
      hoVaTen = fieldData.title?.[0]?.plain_text || 'Anh/Chị';
    }
  }
}

// Fallback if no HR email
if (!hrEmail) {
  hrEmail = clarData.fallbackPrimary; // vynnl@esuhai.com
  ccEmail = clarData.fallbackCC; // hoangkha@esuhai.com
  emailResolutionLog.push('⚠️ HR lookup failed or empty');
  emailResolutionLog.push('⚠️ Using fallback: ' + hrEmail);
  emailResolutionLog.push('⚠️ CC added: ' + ccEmail);
}

console.log('=== HR/FALLBACK BRANCH ===');
emailResolutionLog.forEach(log => console.log(log));

// ========== BUILD PREFILL URL ==========
const FORM_URL = 'https://docs.google.com/forms/d/e/1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw/viewform?usp=pp_url';

const ENTRY_IDS = {
  'clarificationId': 'entry.1684171280',
  'tieuDe': 'entry.1878008034',
  'noiDungGoc': 'entry.1953342780',
  't2NhiemVu': 'entry.1839616630',
  't3ChiTieu': 'entry.649583359',
  't4ThoiHan': 'entry.1319518938',
  'uuTien': 'entry.1910876946',
  'nguonGiaoViec': 'entry.1661283634'
};

const params = {
  [ENTRY_IDS['clarificationId']]: clarData.clarificationId,
  [ENTRY_IDS['tieuDe']]: clarData.tieuDe,
  [ENTRY_IDS['noiDungGoc']]: clarData.noiDungGoc,
  [ENTRY_IDS['t2NhiemVu']]: clarData.t2NhiemVu,
  [ENTRY_IDS['t3ChiTieu']]: clarData.t3ChiTieu,
  [ENTRY_IDS['t4ThoiHan']]: clarData.t4ThoiHan,
  [ENTRY_IDS['uuTien']]: clarData.uuTien,
  [ENTRY_IDS['nguonGiaoViec']]: clarData.nguonGiaoViec
};

const queryString = Object.keys(params)
  .map(key => key + '=' + encodeURIComponent(params[key] || ''))
  .join('&');

const prefillUrl = FORM_URL + '&' + queryString;

// Status message
const statusMessage = clarData.has4T 
  ? '✅ Chỉ đạo đã có đủ 4T. Vui lòng XÁC NHẬN và CAM KẾT thực hiện.'
  : '⚠️ Chỉ đạo còn thiếu thông tin. Vui lòng BỔ SUNG các trường còn trống.';

return {
  ...clarData,
  hrEmail,
  hoVaTen,
  ccEmail,
  prefillUrl,
  statusMessage,
  emailResolutionLog
};
